const baseUrl = 'http://duckdb-service:8001/query';
const database = '/data/vault.duckdb';
const listSql =
  "SELECT table_name FROM information_schema.tables WHERE table_schema = 'main' ORDER BY table_name";

return (async () => {
  const listRes = await this.helpers.httpRequest({
    method: 'POST',
    url: baseUrl,
    headers: { 'content-type': 'application/json' },
    body: { sql: listSql, database },
    json: true,
  });

  const rows = listRes.rows || [];
  const byName = {};
  for (const r of rows) {
    const name = r.table_name;
    if (!name) continue;
    byName[name] = { table_name: name, max_insert_dts: null, row_count: null };
  }
  const vaultRows = rows.filter((r) => { const n = String(r.table_name || ''); return n.startsWith('hub_') || n.startsWith('lnk_') || n.startsWith('sat_'); });
  try {
    if (vaultRows.length > 0) {
      const countSql = vaultRows.map((r) => { const n = String(r.table_name); return "SELECT '" + n.replace(/'/g, "''") + "' AS table_name, COUNT(*) AS row_count FROM \"" + n.replace(/"/g, '""') + '"'; }).join(' UNION ALL ');
      const countRes = await this.helpers.httpRequest({ method: 'POST', url: baseUrl, headers: { 'content-type': 'application/json' }, body: { sql: countSql, database }, json: true });
      for (const r of countRes.rows || []) { if (byName[r.table_name]) byName[r.table_name].row_count = r.row_count; }
    }
  } catch (e) {}
  const marts = rows.filter((r) => String(r.table_name || '').startsWith('mart_'));
  try {
    if (marts.length > 0) {
      const unionSql = marts
        .map((r) => {
          const n = String(r.table_name);
          const safeIdent = n.replace(/"/g, '""');
          return (
            "SELECT '" +
            n.replace(/'/g, "''") +
            "' AS table_name, MAX(mart_insert_dts) AS max_insert_dts FROM \"" +
            safeIdent +
            '"'
          );
        })
        .join(' UNION ALL ');
      const martRes = await this.helpers.httpRequest({
        method: 'POST',
        url: baseUrl,
        headers: { 'content-type': 'application/json' },
        body: { sql: unionSql, database },
        json: true,
      });
      for (const r of martRes.rows || []) {
        const tn = r.table_name;
        if (Object.prototype.hasOwnProperty.call(byName, tn)) {
          byName[tn].max_insert_dts = r.max_insert_dts;
        }
      }
    }
  } catch (e) {
    // mart_insert_dts may be missing or table not readable; leave max_insert_dts null
  }

  // Read vault registry
  let vaultRegistry = [];
  try {
    const vrRes = await this.helpers.httpRequest({
      method: 'POST',
      url: baseUrl,
      headers: { 'content-type': 'application/json' },
      body: { sql: 'SELECT * FROM _vault_registry ORDER BY table_type, table_name', database },
      json: true,
    });
    vaultRegistry = vrRes.rows || [];
  } catch (e) {}

  // Read mart registry
  let martRegistry = [];
  try {
    const mrRes = await this.helpers.httpRequest({
      method: 'POST',
      url: baseUrl,
      headers: { 'content-type': 'application/json' },
      body: { sql: 'SELECT * FROM _mart_registry ORDER BY table_name', database },
      json: true,
    });
    martRegistry = mrRes.rows || [];
  } catch (e) {}

  return [{ json: { output: { data: Object.values(byName) }, vault_registry: vaultRegistry, mart_registry: martRegistry } }];
})();

const inspectResult = $input.first().json;
const webhookData = $('Webhook').first().json.body;
const catalogFile = $('Read Source Catalog').first().json;
let catalog;
try {
  if (catalogFile.data) catalog = JSON.parse(Buffer.from(catalogFile.data, 'base64').toString('utf-8'));
  else catalog = catalogFile;
} catch(e) { catalog = catalogFile; }
const tables = inspectResult.output ? (inspectResult.output.data || []) : [];
const now = new Date();
const H24 = 24*60*60*1000;
const H48 = 48*60*60*1000;
const existingTables = [];
const staleMarts = [];
const expiredMarts = [];
const freshMarts = [];
for (const t of tables) {
  const name = t.table_name;
  existingTables.push(name);
  if (name.startsWith('mart_')) {
    const age = t.max_insert_dts && t.max_insert_dts !== 'NaT'
      ? (now - new Date(t.max_insert_dts))
      : Infinity;
    if (isNaN(age) || age > H48) expiredMarts.push(name);
    else if (age > H24) staleMarts.push(name);
    else freshMarts.push(name);
  }
}
return [{
  json: {
    user_request: webhookData.user_request,
    catalog,
    existing_tables: existingTables,
    fresh_marts: freshMarts,
    stale_marts: staleMarts,
    expired_marts: expiredMarts,
    vault_tables: tables.filter(t => (t.table_name.startsWith('hub_') || t.table_name.startsWith('lnk_') || t.table_name.startsWith('sat_')) && t.row_count > 0).map(t => t.table_name),
    empty_vault_tables: tables.filter(t => (t.table_name.startsWith('hub_') || t.table_name.startsWith('lnk_') || t.table_name.startsWith('sat_')) && t.row_count === 0).map(t => t.table_name),
    vault_registry: inspectResult.vault_registry || [],
    mart_registry: inspectResult.mart_registry || []
  }
}];

const data = $('Classify Tables').first().json;
const currentTables = data.existing_tables.filter(t => !data.expired_marts.includes(t));
const vaultRegistry = data.vault_registry || [];
const martRegistry = data.mart_registry || [];

// ── Format vault metadata ────────────────────────────────────────────────────
const hubs = vaultRegistry.filter(r => r.table_type === 'HUB');
const links = vaultRegistry.filter(r => r.table_type === 'LINK');
const sats = vaultRegistry.filter(r => r.table_type === 'SATELLITE');

let vaultMeta = 'VAULT TABLE METADATA:\n';
vaultMeta += 'HUBS:\n';
if (hubs.length) {
  for (const h of hubs) {
    vaultMeta += '  - ' + h.table_name + ' (PK: ' + (h.pk_column || '?') + ', BK: ' + (h.bk_column || '?') + ', source: ' + (h.source_tables || '?') + ')\n';
  }
} else {
  vaultMeta += '  (none)\n';
}
vaultMeta += 'LINKS:\n';
if (links.length) {
  for (const l of links) {
    vaultMeta += '  - ' + l.table_name + ' (PK: ' + (l.pk_column || '?') + ', connects: ' + (l.hub_keys || '?') + ')\n';
  }
} else {
  vaultMeta += '  (none)\n';
}
vaultMeta += 'SATELLITES:\n';
if (sats.length) {
  for (const s of sats) {
    vaultMeta += '  - ' + s.table_name + ' (parent: ' + (s.parent_table || '?') + ', key: ' + (s.parent_key || '?') + ', columns: ' + (s.columns || '?') + ')\n';
  }
} else {
  vaultMeta += '  (none)\n';
}

// ── Format mart metadata ─────────────────────────────────────────────────────
// freshMarts is already filtered to <24h marts still in currentTables
const freshMartNames = new Set(data.fresh_marts || []);
let martMeta = 'EXISTING MARTS:\n';
if (martRegistry.length) {
  for (const m of martRegistry) {
    const freshLabel = freshMartNames.has(m.table_name) ? '[FRESH]' : '[STALE]';
    martMeta += '  - ' + m.table_name + ' ' + freshLabel + '\n';
    martMeta += '    Answers: ' + (m.understood_request || '?') + '\n';
    martMeta += '    Grain: ' + (m.grain || '?') + '\n';
    martMeta += '    Columns: ' + (m.columns || '?') + '\n';
    martMeta += '    Built from: ' + (m.source_vault_tables || '?') + '\n';
  }
} else {
  martMeta += '  (none)\n';
}

const context = "USER QUESTION: " + data.user_request +
  "\n\nSOURCE CATALOG:\n" + JSON.stringify(data.catalog, null, 2) +
  "\n\n" + vaultMeta +
  "\n" + martMeta +
  "\nEMPTY VAULT TABLES (0 rows, need rebuilding):\n" + ((data.empty_vault_tables || []).length ? data.empty_vault_tables.join(", ") : "(none)");

return [{
  json: {
    llm_context: context,
    user_request: data.user_request,
    catalog: data.catalog,
    existing_tables: currentTables,
    fresh_marts: data.fresh_marts,
    stale_marts: data.stale_marts,
    vault_tables: data.vault_tables,
    empty_vault_tables: data.empty_vault_tables || [],
    vault_registry: vaultRegistry,
    mart_registry: martRegistry
  }
}];

const llmOutput = $input.first().json.text;
let plan;
try { plan = JSON.parse(llmOutput); } catch(e) {
  const m = llmOutput.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (m) plan = JSON.parse(m[1].trim());
  else throw new Error('Cannot parse route: ' + llmOutput.substring(0,200));
}
const ctx = $('Build LLM Context').first().json;

// Enforce final_query to query the generated mart.
// This prevents the router LLM from producing incorrect vault joins.
const martTable = plan.mart_table_name || plan.mart_used;
if (martTable) plan.final_query = 'SELECT * FROM ' + martTable;

// Ensure mart_sql_plan is present; null for QUERY_ONLY and QUERY_SOURCE
if (!('mart_sql_plan' in plan) || plan.mart_sql_plan === null || plan.mart_sql_plan === undefined) {
  plan.mart_sql_plan = (plan.routing_decision === 'QUERY_ONLY' || plan.routing_decision === 'QUERY_SOURCE') ? null : {};
}

// QUERY_SOURCE: no extraction or vault build needed
if (plan.routing_decision === 'QUERY_SOURCE') {
  plan.source_tables_to_extract = [];
  plan.vault_tables_to_create = [];
  plan.mart_sql_plan = null;
}


return [{
  json: {
    ...plan,
    catalog: ctx.catalog,
    existing_tables: ctx.existing_tables,
    vault_tables: ctx.vault_tables
  }
}];

const baseUrl = 'http://duckdb-service:8001/query';
const database = '/data/vault.duckdb';
const sql = String($json.final_query || '').trim();
if (!sql) {
  return [{
    json: {
      status: 'error',
      output: { error: 'final_query is empty', columns: [], data: [], row_count: 0, sql: '' },
    },
  }];
}

return (async () => {
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: baseUrl,
      headers: { 'content-type': 'application/json' },
      body: { sql, database },
      json: true,
    });
    return [{
      json: {
        status: 'success',
        output: {
          columns: res.columns || [],
          data: res.rows || [],
          row_count: res.row_count ?? (res.rows || []).length,
          sql,
          explanation: 'Executed via duckdb-service',
        },
      },
    }];
  } catch (e) {
    let detail = e.message || String(e);
    const d = e.response?.data ?? e.response?.body;
    if (d && typeof d === 'object' && d.detail) detail = String(d.detail);
    if (typeof d === 'string') {
      try {
        const p = JSON.parse(d);
        if (p.detail) detail = String(p.detail);
      } catch (_) {}
    }
    return [{
      json: {
        status: 'error',
        output: { error: detail, columns: [], data: [], row_count: 0, sql },
      },
    }];
  }
})();

const result = $input.first().json;
const plan = $('Parse Route').first().json;
const topStatus = result.status === 'error' ? 'error' : 'success';
const finalSql = (result.output && result.output.sql) || plan.final_query || '';
const queryCode = '-- QUERY_ONLY: Reusing existing mart\n-- Mart: ' + (plan.mart_table_name || '') + '\n\n' + finalSql + '\n';
return [{
  json: {
    status: topStatus,
    routing: 'QUERY_ONLY',
    understood_request: plan.understood_request,
    mart_used: plan.mart_table_name,
    existing_tables_reused: plan.existing_tables_to_reuse || [],
    query_code: queryCode,
    output: result.output || result
  }
}];

const plan = $json;
const tables = plan.source_tables_to_extract || [];
const _ts_start = Date.now();

return (async () => {
  const stagingTables = [];
  const statements = [];

  function inferDuckDBType(values) {
    const nonNull = values.filter(v => v !== null && v !== undefined && v !== '');
    if (!nonNull.length) return 'VARCHAR';
    const sample = nonNull.slice(0, 20);

    // Boolean
    if (sample.every(v => v === true || v === false || v === 'true' || v === 'false')) return 'BOOLEAN';

    // Integer
    if (sample.every(v => {
      const n = Number(v);
      return !isNaN(n) && Number.isInteger(n) && String(v).indexOf('.') === -1;
    })) return 'BIGINT';

    // Double
    if (sample.every(v => !isNaN(Number(v)))) return 'DOUBLE';

    // Date/timestamp (ISO-ish strings)
    if (sample.every(v => typeof v === 'string' && /^\d{4}-\d{2}-\d{2}/.test(v))) {
      if (sample.some(v => /T\d{2}:\d{2}/.test(v))) return 'TIMESTAMP';
      return 'DATE';
    }

    return 'VARCHAR';
  }

  function escapeSingleQuote(val) {
    if (val === null || val === undefined) return 'NULL';
    return "'" + String(val).replace(/'/g, "''") + "'";
  }

  function buildLiteral(val, type) {
    if (val === null || val === undefined || val === '') return 'NULL';
    if (type === 'BOOLEAN') return (val === true || val === 'true') ? 'TRUE' : 'FALSE';
    if (type === 'BIGINT' || type === 'DOUBLE') return String(val);
    if (type === 'DATE') return 'DATE ' + escapeSingleQuote(String(val).slice(0, 10));
    if (type === 'TIMESTAMP') return 'TIMESTAMP ' + escapeSingleQuote(String(val).slice(0, 23));
    return escapeSingleQuote(val);
  }

  for (const fullRef of tables) {
    const parts = fullRef.split('.');
    const stgName = 'stg_' + parts[0] + '_' + parts[1];

    // Call Query Agent
    let qaResult;
    try {
      qaResult = await this.helpers.httpRequest({
        method: 'POST',
        url: 'http://localhost:5678/webhook/query-agent',
        headers: { 'content-type': 'application/json' },
        body: {
          task: 'Extract all rows and all columns from ' + fullRef + '. Do not apply any LIMIT.',
          database: '/data/source.duckdb'
        },
        json: true,
        timeout: 120000,
      });
    } catch (e) {
      const detail = e.response?.data?.detail || e.message || String(e);
      throw new Error('Query Agent failed for ' + fullRef + ': ' + detail);
    }

    if (!qaResult || qaResult.status !== 'success') {
      throw new Error('Query Agent returned non-success for ' + fullRef + ': ' + JSON.stringify(qaResult).slice(0, 400));
    }

    const columns = qaResult.output.columns || [];
    const rows = qaResult.output.data || [];

    if (!columns.length) {
      throw new Error('Query Agent returned no columns for ' + fullRef);
    }

    // Infer types from data
    const colTypes = columns.map((col, i) => {
      const vals = rows.map(row => Array.isArray(row) ? row[i] : row[col]);
      return { name: col, type: inferDuckDBType(vals) };
    });

    // DROP + CREATE TABLE
    statements.push('DROP TABLE IF EXISTS ' + stgName);
    const colDefs = colTypes.map(c => '"' + c.name + '" ' + c.type).join(', ');
    statements.push('CREATE TABLE ' + stgName + ' (' + colDefs + ')');

    // INSERT rows in batches of 500
    const batchSize = 500;
    for (let offset = 0; offset < rows.length; offset += batchSize) {
      const batch = rows.slice(offset, offset + batchSize);
      const colNames = columns.map(c => '"' + c + '"').join(', ');
      const valueRows = batch.map(row => {
        const vals = colTypes.map((c, i) => {
          const v = Array.isArray(row) ? row[i] : row[c.name];
          return buildLiteral(v, c.type);
        });
        return '(' + vals.join(', ') + ')';
      });
      statements.push('INSERT INTO ' + stgName + ' (' + colNames + ') VALUES ' + valueRows.join(', '));
    }

    stagingTables.push({ name: stgName, original_source: fullRef });
  }

  return [{
    json: {
      staging_statements: statements,
      staging_tables: stagingTables,
      plan: plan,
      _ts_start: _ts_start
    }
  }];
})();

const colData = $input.first().json;
const stgData = $('Create Staging Tables').first().json;
const plan = stgData.plan;
const colsByTable = {};
for (const r of (colData.rows || [])) {
  if (!colsByTable[r.table_name]) colsByTable[r.table_name] = [];
  colsByTable[r.table_name].push({name: r.name, type: r.type});
}
const stagingTables = stgData.staging_tables.map(t => ({
  name: t.name,
  original_source: t.original_source,
  columns: colsByTable[t.name] || []
}));
const classifyData = $('Classify Tables').first().json;
return [{
  json: {
    vault_request: {
      staging_tables: stagingTables,
      vault_tables_to_create: plan.vault_tables_to_create || [],
      existing_vault_tables: plan.existing_tables_to_reuse || [],
      business_keys: plan.business_keys || [],
      vault_registry: classifyData.vault_registry || [],
      mart_registry: classifyData.mart_registry || []
    },
    plan: plan
  }
}];

const body = $json.vault_request;
const _ts_start = Date.now();
return (async () => {
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://localhost:5678/webhook/data-vault-agent',
      headers: { 'content-type': 'application/json' },
      body,
      json: true,
      timeout: 120000,
    });

    const result = (res && typeof res === 'object') ? res : { value: res };
    result._ts_vault_ms = Date.now() - _ts_start;
    return [{ json: result }];
  } catch (e) {
    let detail = e.message || String(e);
    const raw = e.response?.data ?? e.response?.body;

    if (raw && typeof raw === 'object' && raw.detail) detail = String(raw.detail);
    else if (typeof raw === 'string' && raw.length) {
      try {
        const p = JSON.parse(raw);
        if (p.detail) detail = String(p.detail);
      } catch (_) {}
      detail = raw.slice(0, 800);
    }

    return [{
      json: {
        status: 'error',
        error: detail,
        vault_tables: [],
        _ts_vault_ms: Date.now() - _ts_start,
      },
    }];
  }
})();

const vaultResult = $input.first().json;
const plan = $('Build Vault Request').first().json.plan;
const vaultTables = vaultResult.vault_tables || [];
const drops = vaultTables.map(t => 'DROP TABLE IF EXISTS ' + t.table_name);
const ddl = vaultTables.map(t => t.ddl);
const loads = vaultTables.map(t => t.load_sql);

// ── Registry helpers ─────────────────────────────────────────────────────────
function extractColumns(ddlStr) {
  if (!ddlStr) return [];
  const m = ddlStr.match(/\((.+)\)/s);
  if (!m) return [];
  const inner = m[1]; const cols = []; let depth = 0; let cur = ''; for (const ch of inner) { if (ch === '(') { depth++; cur += ch; } else if (ch === ')') { depth--; cur += ch; } else if (ch === ',' && depth === 0) { cols.push(cur.trim()); cur = ''; } else { cur += ch; } } if (cur.trim()) cols.push(cur.trim()); return cols.map(c => c.split(/\s+/)[0]).filter(Boolean);
}

function safeStr(s) {
  return String(s || '').replace(/'/g, "''");
}

// Build registry DDL + inserts for vault tables
const registryDDL = `CREATE TABLE IF NOT EXISTS _vault_registry (
  table_name   VARCHAR PRIMARY KEY,
  table_type   VARCHAR NOT NULL,
  pk_column    VARCHAR,
  bk_column    VARCHAR,
  hub_keys     VARCHAR,
  parent_table VARCHAR,
  parent_key   VARCHAR,
  source_tables VARCHAR,
  columns      VARCHAR,
  created_dts  TIMESTAMP DEFAULT CURRENT_TIMESTAMP
)`;

const registryStmts = [registryDDL];

for (const t of vaultTables) {
  if (!t || !t.table_name) continue;
  const cols = extractColumns(t.ddl || '');
  const tableType = t.table_type || (
    t.table_name.startsWith('hub_') ? 'HUB' :
    t.table_name.startsWith('lnk_') ? 'LINK' :
    t.table_name.startsWith('sat_') ? 'SATELLITE' : 'UNKNOWN'
  );

  // source tables: find stg_xxx_yyy patterns in load_sql, convert to xxx.yyy
  const loadSql = t.load_sql || '';
  const stgMatches = [...loadSql.matchAll(/stg_([a-z]+)_([a-z_]+)/gi)];
  const srcSet = new Set(stgMatches.map(m => m[1] + '.' + m[2]));
  const sourceTables = [...srcSet].join(',');

  let pkColumn = '';
  let bkColumn = '';
  let hubKeys = '';
  let parentKey = '';
  let parentTable = '';

  if (tableType === 'HUB') {
    pkColumn = cols.find(c => c.endsWith('_hk')) || '';
    bkColumn = cols.find(c => c.endsWith('_bk')) || '';
  } else if (tableType === 'LINK') {
    const hkCols = cols.filter(c => c.endsWith('_hk'));
    pkColumn = hkCols[0] || '';
    hubKeys = hkCols.slice(1).join(',');
  } else if (tableType === 'SATELLITE') {
    parentKey = cols.find(c => c.endsWith('_hk')) || '';
    // Try to resolve parent from sibling tables in this batch
    const sibling = vaultTables.find(s => {
      if (!s || !s.table_name || s.table_name === t.table_name) return false;
      const sibCols = extractColumns(s.ddl || '');
      return sibCols[0] === parentKey;
    });
    parentTable = sibling ? sibling.table_name : '';
  }

  const colList = cols.join(',');
  const tn = safeStr(t.table_name);

  registryStmts.push(`DELETE FROM _vault_registry WHERE table_name = '${tn}'`);
  registryStmts.push(
    `INSERT INTO _vault_registry (table_name, table_type, pk_column, bk_column, hub_keys, parent_table, parent_key, source_tables, columns) VALUES (` +
    `'${tn}', '${safeStr(tableType)}', '${safeStr(pkColumn)}', '${safeStr(bkColumn)}', ` +
    `'${safeStr(hubKeys)}', '${safeStr(parentTable)}', '${safeStr(parentKey)}', ` +
    `'${safeStr(sourceTables)}', '${safeStr(colList)}')`
  );
}

// UPDATE to resolve satellite parents from existing registry entries (for PARTIAL_BUILD)
registryStmts.push(
  `UPDATE _vault_registry SET parent_table = (` +
  `SELECT vr2.table_name FROM _vault_registry vr2 ` +
  `WHERE vr2.pk_column = _vault_registry.parent_key ` +
  `AND vr2.table_type IN ('HUB','LINK') LIMIT 1) ` +
  `WHERE table_type = 'SATELLITE' AND (parent_table IS NULL OR parent_table = '')`
);

return [{
  json: {
    vault_statements: [...drops, ...ddl, ...loads, ...registryStmts],
    vault_tables: vaultTables,
    plan: plan
  }
}];

const statements = $json.vault_statements || [];

const res = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://duckdb-service:8001/execute-batch',
  headers: { 'content-type': 'application/json' },
  body: { statements, database: '/data/vault.duckdb' },
  json: true,
});

const results = res.results || [];
const failed = results.filter(r => r.status === 'error');

if (failed.length > 0) {
  for (const f of failed) {
    const preview = (statements[f.index] || '').slice(0, 120).replace(/\s+/g, ' ');
    console.error(
      '[Execute Vault SQL] Statement ' + f.index + ' failed: ' + (f.error || 'unknown error') +
      ' | SQL preview: ' + preview
    );
  }
}

return [{ json: { 
  ...res, 
  exec_errors: failed.map(f => ({
    index: f.index,
    error: f.error,
    sql_preview: (statements[f.index] || '').slice(0, 200).replace(/\s+/g, ' ')
  }))
}}];

const prev = $('Collect Vault SQL').first().json;
const plan = prev.plan;

return (async () => {
  const createdVaultTables = prev.vault_tables || [];
  const vaultByName = {};

