      (tableColMap[p.table_name] || [])[0] === parentHk
    );
    if (parentTable) {
      checks.push(
        `SELECT '${name}_ref_${parentTable.table_name}', '${name}', 'REFERENTIAL',` +
        ` 'Orphan records in ${name} referencing ${parentTable.table_name}',` +
        ` COUNT(*) FROM "${name}" s WHERE s."${parentHk}" NOT IN (SELECT "${parentHk}" FROM "${parentTable.table_name}")`
      );
    }
  }

  if (tableType === 'LINK') {
    // Each _hk column after the first references a hub by naming convention
    const fkHkCols = hkCols.slice(1); // skip the link's own PK (first _hk)
    for (const hk of fkHkCols) {
      // Find hub whose PK column matches this hk
      const refHub = vaultTables.find(p =>
        p && p.table_name !== name &&
        p.table_name.startsWith('hub_') &&
        (tableColMap[p.table_name] || [])[0] === hk
      );
      if (refHub) {
        checks.push(
          `SELECT '${name}_ref_${refHub.table_name}', '${name}', 'REFERENTIAL',` +
          ` 'Orphan ${hk} in ${name}',` +
          ` COUNT(*) FROM "${name}" l WHERE l."${hk}" NOT IN (SELECT "${hk}" FROM "${refHub.table_name}")`
        );
      }
    }
  }
}

const totalChecks = checks.length;

return (async () => {
  try {
    const sql = checks.join(' UNION ALL ');
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: baseUrl,
      headers: { 'content-type': 'application/json' },
      body: { sql, database },
      json: true,
    });

    const rows = res.rows || [];
    const issues = rows
      .filter(r => Number(r.issue_count) > 0)
      .map(r => ({
        severity: r.category === 'COMPLETENESS' && r.check_id.endsWith('_empty') ? 'error' : 'warning',
        table: r.table_name,
        check: r.category,
        message: r.message,
        count: Number(r.issue_count),
      }));

    return [{
      json: {
        status: issues.some(i => i.severity === 'error') ? 'fail' : 'pass',
        checks_run: totalChecks,
        issues,
        exec_errors: execErrors,
        _ts_vault_dq_ms: Date.now() - _ts_start,
      },
    }];
  } catch (e) {
    let detail = e.message || String(e);
    const raw = e.response?.data ?? e.response?.body;
    if (typeof raw === 'string' && raw.length) detail = raw.slice(0, 800);
    else if (raw && typeof raw === 'object') detail = JSON.stringify(raw).slice(0, 800);
    return [{
      json: {
        status: 'error',
        checks_run: totalChecks,
        issues: [{
          severity: 'error',
          table: '_dq_system',
          check: 'SYSTEM',
          message: 'Vault DQ query failed: ' + detail,
          count: 0,
        }],
        exec_errors: execErrors,
        _ts_vault_dq_ms: Date.now() - _ts_start,
      },
    }];
  }
})();

const vaultDQ = $('Call Vault DQ').first().json;
const vaultData = $('Collect Vault SQL').first().json;
const stgData = $('Create Staging Tables').first().json;
const execResult = $('Execute Vault SQL').first().json;
const plan = vaultData.plan;

// Drop staging tables before responding
const dropStmts = (stgData.staging_tables || []).map(t => 'DROP TABLE IF EXISTS ' + t.name);
if (dropStmts.length > 0) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://duckdb-service:8001/execute-batch',
      headers: { 'content-type': 'application/json' },
      body: { statements: dropStmts, database: '/data/vault.duckdb' },
      json: true,
    });
  } catch (e) {}
}

const dqIssues = vaultDQ.issues || [];
const dqStatus = vaultDQ.status || 'fail';

return [{
  json: {
    status: 'error',
    routing: plan ? plan.routing_decision : 'BUILD',
    understood_request: plan ? plan.understood_request : '',
    vault_tables_created: plan ? (plan.vault_tables_to_create || []) : [],
    existing_tables_reused: plan ? (plan.existing_tables_to_reuse || []) : [],
    source_tables_extracted: (stgData.staging_tables || []).map(t => t.original_source),
    dq_status: dqStatus,
    dq_checks_run: vaultDQ.checks_run || 0,
    dq_issues: dqIssues,
    output: {
      error: 'Vault data quality checks failed — ' + dqIssues.length + ' issue(s) found. Vault tables were not committed.',
      columns: [],
      data: [],
      row_count: 0,
      sql: ''
    },
    exec_errors: execResult.exec_errors || [],
    exec_summary: { total: execResult.total, succeeded: execResult.succeeded, failed: execResult.failed }
  }
}];

const plan = $json;
const question = plan.understood_request || '';

return (async () => {
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://localhost:5678/webhook/query-agent',
      headers: { 'content-type': 'application/json' },
      body: {
        task: question,
        database: '/data/source.duckdb'
      },
      json: true,
      timeout: 60000,
    });
    const result = (res && typeof res === 'object') ? res : { value: res };
    return [{ json: { status: 'success', output: result.output || result } }];
  } catch (e) {
    const detail = e.response?.data?.detail || e.message || String(e);
    return [{ json: { status: 'error', output: { error: detail, columns: [], data: [], row_count: 0 } } }];
  }
})();

const result = $input.first().json;
const plan = $('Parse Route').first().json;
const sourceSql = (result.output && result.output.sql) || '';
const queryCode = '-- QUERY_SOURCE: Source database query\n\n' + sourceSql + '\n';
return [{
  json: {
    status: result.status || 'success',
    routing: 'QUERY_SOURCE',
    understood_request: plan.understood_request,
    query_code: queryCode,
    output: result.output || result
  }
}];
